using UnityEditor;
using UnityEngine;

public class AvatarChecker
{
    public static string Check()
    {
        // PlayerModel Animator InstanceID: 54502
        Animator anim = (Animator)EditorUtility.InstanceIDToObject(54502);
        if (anim == null) return "Animator not found on PlayerModel";
        if (anim.avatar == null) return "Avatar is null on PlayerModel Animator";
        return $"Animator Avatar: {anim.avatar.name} (InstanceID: {anim.avatar.GetInstanceID()})";
    }
}
